function formatAttributeLabel(key: string): string {
  const mapped = ATTRIBUTE_LABELS[key]
  if (mapped) return mapped

  const tail = key.split('.').pop() ?? key
  const words = tail.split('_').filter(Boolean)
  if (words.length === 0) return key
